sql:
SELECT COUNT(*) 
FROM lottery_games 
WHERE country = '1';

SELECT prize_per_winner
FROM prize_tiers
WHERE prize_per_winner > '100000';

SELECT game_name, country, MAX(game_max_tickets_per_customer) AS max_tickets_per_game
FROM lottery_games
GROUP BY game_name, country;

SELECT tier_name
FROM prize_tiers
WHERE tier_id = 1;

SELECT tier_id, SUM(prize_fund_amount) AS total_prize_fund
FROM prize_funds
GROUP BY tier_id;

SELECT game_name, game_max_tickets_per_customer
FROM lottery_games
ORDER BY game_max_tickets_per_customer DESC;

external_knowledge:
- External knowledge is not explicitly needed for this query but may include general knowledge about lottery systems and payout calculations; 
- Each country has its own tax rate applied to lottery winnings; 
- Estonian winners refer to winners residing in Estonia.
